const outputItems = items
  .map(({ json }) => {

    if (
      !json ||
      json.Generate_Title_Description !== 'yes' ||
      (
        json.Title_Shopify &&
        json.Description_Shopify
      )
    ) {
      return null;
    }

    const keyword =
      json['Keywords (Luna)'] ?? '';

    const dimensions =
      normalizeDimensions(json);

    return {
      json: {
        row_number:
          json.row_number ?? 0,

        sheet_name:
          CONFIG.SHEET_NAME,

        keyword,

        Image_Url:
          json['IMAGE URL3'],

        material:
          json.Material ?? '',

        finish:
          json.Finish ?? '',

        dimensions,

        prompt: CONFIG.SHEET_NAME === 'Wall-Coverings' || CONFIG.SHEET_NAME === 'Exterior-Wall-Decoration'
          ? buildWallCoveringPrompt({
              keyword,
              material: json.Material ?? '',
              finish:   json.Finish   ?? '',
            })
          : CONFIG.SHEET_NAME === 'Fireplace'
          ? buildFireplacePrompt({
              keyword,
              material:   json.Material   ?? '',
              finish:     json.Finish     ?? '',
              dimensions,
            })
          : buildPrompt({
              sheetName:   CONFIG.SHEET_NAME,
              dimensions,
              material:    json.Material ?? '',
              keyword,
              finish:      json.Finish   ?? '',
              promptRules: json.Prompt_Rules ?? '',
            }),
      },
    };

  })
  .filter(Boolean);

return outputItems.length
  ? outputItems
  : null;

// ============================================
// CONTEXT
// ============================================
const { sheet_name, row_number } =
  $('🔁 Iterate Products for AI Analysis').item.json;

// ============================================
// UTILITIES
// ============================================

const cleanText = (text = '') =>
  String(text)
    .replace(/\s+/g, ' ')
    .trim();

// ============================================
// MAIN
// ============================================

const outputItems = items
  .map(({ json }) => {

    // ----------------------------------------
    // RAW AI OUTPUT
    // ----------------------------------------
    const raw =
      json?.content?.parts?.[0]?.text?.trim();

    if (!raw) return null;

    let parsed;

    try {

      // ----------------------------------------
      // SAFETY CLEANING
      // Handles accidental ```json fences
      // ----------------------------------------
      const cleaned = raw
        .replace(/```json/g, '')
        .replace(/```/g, '')
        .trim();

      parsed = JSON.parse(cleaned);

    } catch (err) {

      // ----------------------------------------
      // RETURN DEBUG INFO IF PARSING FAILS
      // ----------------------------------------
      return {
        json: {
          sheet_name,
          row_number,
          parsing_error: true,
          parsing_error_message: err.message,
          raw_output: raw
        }
      };
    }

    // ========================================
    // SUCCESS OUTPUT
    // ========================================
    return {
      json: {

        sheet_name,
        row_number,

        // ------------------------------------
        // SHOPIFY
        // ------------------------------------
        Title_Shopify: cleanText(
          parsed?.version1?.title
        ),

        Description_Shopify: cleanText(
          parsed?.version1?.description
        ),

        // ------------------------------------
        // ETSY
        // ------------------------------------
        Title_Etsy: cleanText(
          parsed?.version2?.title
        ),

        Description_Etsy: cleanText(
          parsed?.version2?.description
        ),

        // ------------------------------------
        // SEO
        // ------------------------------------
        Shopify_SEO_Title: cleanText(
          parsed?.seo?.title
        ),

        Shopify_SEO_Description: cleanText(
          parsed?.seo?.meta_description
        ),

        // ------------------------------------
        // STATUS
        // ------------------------------------
        Generate_Title_Description: 'no'
      }
    };

  })
  .filter(Boolean);

return outputItems;
